#!/usr/bin/env node
/**
 * Rebuild every index.md in the node reference tree (docs/nodes) from the node
 * pages that actually exist on disk.
 *
 * Why this exists: the per-node pages, their directory layout, and the various
 * hand-rolled index pages were generated by different runs at different times,
 * so the indexes drifted out of sync — wrong totals, missing namespaces
 * (`huggingface`, `mlx`), and links to renamed/removed children that 404. This
 * regenerates the indexes straight from the files on disk, so no index can link
 * to something that isn't there, regardless of which generator produced the
 * pages.
 *
 *   - Root  docs/nodes/index.md   : every leaf namespace, grouped by top segment.
 *   - Each subdirectory index.md  : its immediate sub-namespaces + node pages.
 *
 * Labels come from the `namespace:` front matter of the contained pages (which
 * is consistent per directory); links always point at real directories/files.
 *
 * Usage:
 *   node scripts/build-node-index.mjs
 *   node scripts/build-node-index.mjs --nodes-dir docs/nodes
 */
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const repoRoot = path.resolve(__dirname, "..");

const args = process.argv.slice(2);
let nodesDir = path.join(repoRoot, "docs", "nodes");
for (let i = 0; i < args.length; i++) {
  if (args[i] === "--nodes-dir" && args[i + 1]) nodesDir = path.resolve(args[++i]);
}

function frontMatter(file, key) {
  const text = fs.readFileSync(file, "utf8");
  const m = text.match(new RegExp(`^${key}:\\s*"?([^"\\n]+)"?\\s*$`, "m"));
  return m ? m[1].trim() : null;
}

/** Immediate subdirectories of a directory. Skips dot/underscore names, which
 *  Jekyll excludes from the built site (so linking to them would 404). */
const subdirs = (dir) =>
  fs
    .readdirSync(dir, { withFileTypes: true })
    .filter((e) => e.isDirectory() && !/^[._]/.test(e.name))
    .map((e) => e.name)
    .sort();

/** Immediate node pages (markdown, excluding index.md). */
const pageFiles = (dir) =>
  fs
    .readdirSync(dir, { withFileTypes: true })
    .filter((e) => e.isFile() && e.name.endsWith(".md") && e.name !== "index.md")
    .map((e) => e.name)
    .sort();

/** Recursive node-page count under a directory. */
function countNodes(dir) {
  let n = pageFiles(dir).length;
  for (const sd of subdirs(dir)) n += countNodes(path.join(dir, sd));
  return n;
}

/** Namespace label for a directory: prefer a contained page's front matter. */
function dirNamespace(dir) {
  for (const p of pageFiles(dir)) {
    const ns = frontMatter(path.join(dir, p), "namespace");
    if (ns) return ns;
  }
  // Fall back to the directory path relative to nodes/.
  const rel = path.relative(nodesDir, dir).split(path.sep).join(".");
  return rel || "nodes";
}

// --- Root index: every leaf namespace grouped by top segment -----------------
function writeRootIndex() {
  const leaves = [];
  (function walk(dir) {
    if (pageFiles(dir).length > 0 && dir !== nodesDir) {
      leaves.push({
        rel: path.relative(nodesDir, dir).split(path.sep).join("/"),
        namespace: dirNamespace(dir),
        count: pageFiles(dir).length,
      });
    }
    for (const sd of subdirs(dir)) walk(path.join(dir, sd));
  })(nodesDir);

  const total = leaves.reduce((s, l) => s + l.count, 0);
  const groups = new Map();
  for (const l of leaves) {
    const g = l.namespace.split(".")[0];
    if (!groups.has(g)) groups.set(g, []);
    groups.get(g).push(l);
  }

  const out = [
    "---",
    "layout: page",
    'title: "Node Reference"',
    "---",
    "",
    `Complete reference documentation for all ${total} NodeTool nodes across ${leaves.length} namespaces.`,
    "",
    "## Namespaces",
    "",
  ];
  for (const [g, list] of [...groups.entries()].sort((a, b) => a[0].localeCompare(b[0]))) {
    out.push(`### ${g}`, "");
    for (const l of list.sort((a, b) => a.namespace.localeCompare(b.namespace)))
      out.push(`- **[${l.namespace}](${l.rel}/)** - ${l.count} node(s)`);
    out.push("");
  }
  fs.writeFileSync(path.join(nodesDir, "index.md"), out.join("\n"));
  return { total, namespaces: leaves.length };
}

// --- Per-directory index: immediate sub-namespaces + node pages --------------
function writeDirIndex(dir) {
  const ns = dirNamespace(dir);
  const out = ["---", "layout: page", `title: "${ns} Nodes"`, "---", ""];

  const childDirs = subdirs(dir);
  const pages = pageFiles(dir);
  out.push(`This namespace contains ${countNodes(dir)} node(s).`, "");

  if (childDirs.length > 0) {
    out.push("## Sub-namespaces", "");
    for (const sd of childDirs)
      out.push(`- **[${sd}](${sd}/)** - ${countNodes(path.join(dir, sd))} node(s)`);
    out.push("");
  }

  if (pages.length > 0) {
    out.push("## Nodes", "");
    const rows = pages.map((p) => ({
      file: p,
      title: frontMatter(path.join(dir, p), "title") || p.replace(/\.md$/, ""),
    }));
    for (const r of rows.sort((a, b) => a.title.localeCompare(b.title)))
      out.push(`- **[${r.title}](${r.file})**`);
    out.push("");
  }

  out.push("[Back to all nodes](" + path.relative(dir, nodesDir).split(path.sep).join("/") + "/)", "");
  fs.writeFileSync(path.join(dir, "index.md"), out.join("\n"));
}

function walkDirs(dir) {
  for (const sd of subdirs(dir)) {
    const child = path.join(dir, sd);
    writeDirIndex(child);
    walkDirs(child);
  }
}

const { total, namespaces } = writeRootIndex();
walkDirs(nodesDir);
console.log(`Rebuilt node indexes: ${total} nodes across ${namespaces} namespaces`);
